sql.where:
      AND D.DEL_YN = 'N'

        AND P.DEPT_CD = #{params.deptCd} 


        AND P.PROJECT_STAT_CD = #{params.projectStatCd} 


        AND P.USE_YN = #{params.useYn} 


        AND (P.PROJECT_NM LIKE '%' || #{params.keyword} || '%' OR P.PROJECT_DESC LIKE '%' || #{params.keyword} || '%')


	    AND P.START_DTM >= TO_DATE(#{params.startDate}, 'YYYY-MM-DD') 


	    AND P.END_DTM < TO_DATE(#{params.endDate}, 'YYYY-MM-DD') + 1
